using System.ComponentModel;
using System.Net;
using System.Text.RegularExpressions;
using Microsoft.Extensions.AI;

// --- Configuration ---
var apiKey = Environment.GetEnvironmentVariable("OPENAI_API_KEY");
if (string.IsNullOrEmpty(apiKey))
{
    Console.Error.WriteLine("Error: Set the OPENAI_API_KEY environment variable.");
    return 1;
}

var model = Environment.GetEnvironmentVariable("OPENAI_MODEL") ?? "gpt-4o-mini";

// --- Build chat client with automatic function invocation ---
var tools = new ResearchTools();
IChatClient client = new OpenAI.OpenAIClient(apiKey)
    .GetChatClient(model)
    .AsIChatClient()
    .AsBuilder()
    .UseFunctionInvocation()
    .Build();

var chatOptions = new ChatOptions
{
    Tools =
    [
        AIFunctionFactory.Create(tools.SearchWeb),
        AIFunctionFactory.Create(tools.TakeNote),
        AIFunctionFactory.Create(tools.GetNotes),
    ]
};

// --- Get topic from user ---
string? topic;
if (args.Length > 0)
{
    topic = string.Join(' ', args);
}
else
{
    Console.Write("Enter a research topic: ");
    topic = Console.ReadLine()?.Trim();
}

if (string.IsNullOrWhiteSpace(topic))
{
    Console.Error.WriteLine("No topic provided.");
    return 1;
}

// --- Run the research agent loop ---
var messages = new List<ChatMessage>
{
    new(ChatRole.System, """
        You are a research agent. Your goal is to thoroughly research the given topic
        and produce a well-organized summary.

        Follow this process:
        1. Search the web with a broad query about the topic.
        2. Take notes on the most important findings from each search.
        3. Search for additional subtopics or details to fill knowledge gaps.
        4. Continue searching and note-taking until you have comprehensive coverage.
        5. Retrieve your notes and write a clear, well-structured summary with key facts.

        Guidelines:
        - Perform at least 2-3 different searches to get diverse perspectives.
        - Always take notes after each search before moving to the next one.
        - Keep notes concise but informative.
        - Your final summary should synthesize all your research into a coherent report.
        """),
    new(ChatRole.User, $"Research the following topic and provide a comprehensive summary: {topic}")
};

Console.WriteLine($"\n🔍 Researching: {topic}\n");
Console.WriteLine(new string('─', 50));

var response = await client.GetResponseAsync(messages, chatOptions);

Console.WriteLine(new string('─', 50));
Console.WriteLine("\n📋 Research Summary:\n");
Console.WriteLine(response.Text);

return 0;

// ============================================================
// Tool implementations
// ============================================================

/// <summary>
/// Provides web search and note-taking tools for the research agent.
/// </summary>
public class ResearchTools
{
    private readonly List<string> _notes = [];

    [Description("Search the web for information on a given query. Returns relevant text snippets from search results.")]
    public async Task<string> SearchWeb(
        [Description("The search query string")] string query)
    {
        Console.WriteLine($"  🌐 Searching: \"{query}\"");

        using var http = new HttpClient();
        http.DefaultRequestHeaders.UserAgent.ParseAdd(
            "Mozilla/5.0 (compatible; ResearchAgent/1.0)");

        try
        {
            var url = $"https://html.duckduckgo.com/html/?q={Uri.EscapeDataString(query)}";
            var html = await http.GetStringAsync(url);

            var results = new List<string>();
            foreach (Match m in Regex.Matches(
                html,
                @"result__snippet[^>]*>(.*?)</",
                RegexOptions.Singleline))
            {
                var text = WebUtility.HtmlDecode(
                    Regex.Replace(m.Groups[1].Value, "<[^>]+>", "")).Trim();
                if (!string.IsNullOrWhiteSpace(text))
                    results.Add(text);
                if (results.Count >= 6)
                    break;
            }

            return results.Count > 0
                ? string.Join("\n---\n", results)
                : "No results found. Try rephrasing your query.";
        }
        catch (Exception ex)
        {
            return $"Search failed: {ex.Message}. Try a different query.";
        }
    }

    [Description("Save a research note. Use this to record important findings from your searches.")]
    public string TakeNote(
        [Description("The content of the note to save")] string note)
    {
        _notes.Add(note);
        Console.WriteLine($"  📝 Note #{_notes.Count} saved");
        return $"Note saved successfully. You now have {_notes.Count} note(s).";
    }

    [Description("Retrieve all saved research notes to review before writing your summary.")]
    public string GetNotes()
    {
        if (_notes.Count == 0)
            return "No notes have been saved yet.";

        Console.WriteLine($"  📖 Retrieving {_notes.Count} note(s)");
        return string.Join("\n\n---\n\n",
            _notes.Select((n, i) => $"[Note {i + 1}]\n{n}"));
    }
}

